from __future__ import annotations

from collections import defaultdict
from dataclasses import dataclass
from decimal import Decimal
from typing import TYPE_CHECKING

from django.utils.functional import cached_property

from djmoney.money import Money
from treelib import Node

from cloud.costengine.utils import multiplier_to_percent, percent_to_multiplier
from cloud.financial.invoicing.money import force_money_sum
from cloud.products.enums import PurchaseModel
from cloud.shoppingcart.dataclasses import ShoppingCartInvoicingItem
from cloud.shoppingcart.product_tree.enums import ProductCategory
from cloud.shoppingcart.product_tree.mapping import get_legacy_product_for_product_category

if TYPE_CHECKING:
    from django_stubs_ext import StrOrPromise

    from cloud.costengine.models import CostItem
    from cloud.shoppingcart.models import BaseMarkupRule, CartModification, ExtraItem
    from cloud.shoppingcart.product_tree.hierarchy.tree import ProductTree
    from cloud.shoppingcart.types import HardwareEntry


@dataclass
class ProductNodeData:
    cost_item: CostItem | None = None
    extra_item: ExtraItem | None = None
    cart_modification: CartModification | None = None
    purchase_model: PurchaseModel | None = None
    vat_purchase_model: PurchaseModel | None = None
    base_markup_adjustment: Money | None = None
    base_markup_rule: BaseMarkupRule | None = None
    hardware_override: HardwareEntry | None = None


class ProductNode(Node):
    if TYPE_CHECKING:
        tree: ProductTree
        data: ProductNodeData

    def is_leaf(self, *args, **kwargs) -> bool:
        return super().is_leaf(self.tree.identifier)

    @property
    def product_category(self) -> ProductCategory:
        if self.data.cost_item:
            assert self.parent
            return self.parent.product_category
        elif self.data.extra_item:
            return self.data.extra_item.product_category
        elif self.data.base_markup_adjustment:
            return ProductCategory.SERVICE_OTOVO
        return self.identifier

    @property
    def parent(self) -> ProductNode | None:
        parent_id = self.tree.ancestor(self.identifier)
        if not parent_id:
            return None
        return self.tree.get_node(parent_id)

    @property
    def children(self) -> list[ProductNode]:
        return self.tree.children(self.identifier)

    @property
    def level(self) -> int:
        """
        Get the node's level in its tree. The level is an integer starting with 0 at the root.
        """
        return self.tree.level(self.identifier)

    @property
    def currency(self) -> str:
        return self.tree.shopping_cart.cost.currency

    def get_vat_percent(self, vat_purchase_model: PurchaseModel):
        if self.data.base_markup_adjustment and self.parent:
            product_category = self.parent.product_category
        else:
            product_category = self.product_category
        return self.tree.shopping_cart.get_vat_percent(
            purchase_model=vat_purchase_model,
            product_category=product_category,
        )

    @cached_property
    def vat_percent(self) -> Decimal:
        """
        Provide the VAT rate for this node based on default parameters.

        May raise ValueError if called on root node if multiple VATs exist in the tree
        """
        if self.level == 0:
            child_vats = {
                node.get_vat_percent(vat_purchase_model=self.vat_purchase_model) for node in self.children
            }
            if len(child_vats) == 1:
                return child_vats.pop()
            else:
                raise ValueError(
                    f'Cannot determine VAT from root node, multiple values found among children: ({child_vats})'
                )
        return self.get_vat_percent(vat_purchase_model=self.vat_purchase_model)

    @property
    def vat_multiplier(self) -> Decimal:
        return percent_to_multiplier(self.vat_percent)

    @property
    def base_markup_multiplier(self) -> Decimal:
        if rule := self.data.base_markup_rule:
            return rule.markup_multiplier
        return Decimal(1)

    @property
    def subscription_asset_value_multiplier(self) -> Decimal:
        if self.purchase_model == PurchaseModel.LEASING and (rule := self.data.base_markup_rule):
            return rule.subscription_asset_value_multiplier
        return Decimal(1)

    @property
    def installer_markup_multiplier(self) -> Decimal:
        if (markup := self.tree.installer_markup) and markup.markup_percent is not None:
            return percent_to_multiplier(markup.markup_percent)
        return Decimal('1')

    @property
    def vat_purchase_model(self) -> PurchaseModel:
        if self.data.vat_purchase_model is not None:
            return self.data.vat_purchase_model

        if (parent := self.parent) is not None:
            return parent.vat_purchase_model

        raise ValueError('Could not resolve VAT purchase model in tree: %s', self.tree.identifier)

    @property
    def purchase_model(self) -> PurchaseModel:
        if self.data.purchase_model is not None:
            return self.data.purchase_model

        if (parent := self.parent) is not None:
            return parent.purchase_model

        raise ValueError('Could not resolve purchase model in tree: %s', self.tree.identifier)

    def set_base_markup_rule(self, rule: BaseMarkupRule) -> ProductNode:
        self.data.base_markup_rule = rule
        return self

    def set_cart_modification(self, cart_modification: CartModification | None) -> ProductNode:
        if self.identifier not in [
            ProductCategory.ALL,
            *ProductCategory.get_main_hardware_categories(),
        ]:
            raise ValueError(
                f'Can only add cart modifications to root or group level nodes, not {self.identifier}'
            )

        if self.data.cart_modification:
            raise ValueError(f'Cart modification already set for node {self.identifier}')

        self.data.cart_modification = cart_modification
        return self

    def set_vat_purchase_model(self, vat_purchase_model: PurchaseModel | None) -> ProductNode:
        self.data.vat_purchase_model = vat_purchase_model
        return self

    def set_purchase_model(self, purchase_model: PurchaseModel | None) -> ProductNode:
        self.data.purchase_model = purchase_model
        return self

    def set_hardware_override(self, hardware_override: HardwareEntry) -> ProductNode:
        self.data.hardware_override = hardware_override
        return self

    @property
    def cost_model_cost_unmodified(self) -> Money:
        """
        Returns this node's unmodified cost coming from the cost model.
        It is used as the basis for installer markup.
        """
        if not self.data.cost_item:
            return Money(0, self.currency)

        return self.data.cost_item.total_unmodified_cost

    @property
    def cost_model_cost_modified(self) -> Money:
        """
        Returns this node's modified cost coming from the cost model.
        It is used as the basis for base markup.
        """
        if not self.data.cost_item:
            return Money(0, self.currency)

        return self.data.cost_item.total_modified_cost

    @property
    def base_markup_amount(self) -> Money:
        return self.cost_model_cost_modified * (self.base_markup_multiplier - 1)

    @property
    def installer_markup_amount(self) -> Money:
        return self.cost_model_cost_unmodified * (self.installer_markup_multiplier - 1)

    @property
    def cost_item_marked_up(self) -> Money:
        """Sum of cost model cost, base markup, installer markup, partner markup."""
        if not self.data.cost_item:
            return Money(0, self.currency)

        return self.cost_model_cost_modified + self.base_markup_amount + self.installer_markup_amount

    @property
    def node_base_price(self) -> Money:
        """
        Returns the base price of this node. This is the unmodified total, excl. VAT

        Nodes derive a price from one of three sources:
            1. Extra Item node's total price
            2. Markup Adjustment price
            3. Cost Item fully marked up price

        RETURNS EXCL. VAT
        """
        if self.data.extra_item:
            base_price = self.data.extra_item.total_price
        elif self.data.base_markup_adjustment:
            base_price = self.data.base_markup_adjustment
        else:
            base_price = self.cost_item_marked_up
        if self.purchase_model == PurchaseModel.LEASING:
            base_price *= self.subscription_asset_value_multiplier

        return base_price

    @property
    def node_base_price_modified(self) -> Money:
        """Node base price including CartModification

        RETURNS EXCL. VAT
        """
        return self._apply_modification_to_value(value=self.node_base_price, include_vat=False)

    @property
    def node_gross_price(self) -> Money:
        """Node complete modified gross price

        RETURNS INC. VAT
        """
        if self.is_leaf():
            return self.node_base_price_modified * self.vat_multiplier
        return Money(0, self.currency)

    @property
    def node_gross_price_unmodified(self) -> Money:
        """Node unmodified gross price

        RETURNS INC. VAT
        """
        if self.is_leaf():
            return self.node_base_price * self.vat_multiplier
        return Money(0, self.currency)

    @property
    def vat_base(self) -> Money:
        if self.is_leaf():
            return self.node_gross_price / self.vat_multiplier
        return force_money_sum(
            (child.vat_base for child in self.children),
            currency=self.currency,
        )

    @property
    def vat_amount(self) -> Money:
        if self.is_leaf():
            return self.node_gross_price - self.vat_base
        return force_money_sum(
            (child.vat_amount for child in self.children),
            currency=self.currency,
        )

    @property
    def price_affecting_cart_modification(self) -> CartModification | None:
        """Returns the node's cart mod only if it is not a leasing terms mod"""
        if (mod := self.data.cart_modification) and mod.num_terms_affected is None:
            return mod
        return None

    @property
    def has_price_affecting_cart_modification(self) -> bool:
        """Returns False if no cart mod or if the cart mod is a leasing terms mod"""
        return self.price_affecting_cart_modification is not None

    @property
    def discount_modification_multiplier(self) -> Decimal:
        """return multiplier if it exists on node and is not a Leasing monthly modification"""
        if (
            (mod := self.data.cart_modification)
            and mod.multiplier is not None
            and mod.num_terms_affected is None
        ):
            return mod.multiplier
        return Decimal('1')

    @property
    def modification_multiplier(self) -> Decimal:
        mod = self.data.cart_modification
        if not mod or mod.multiplier is None:
            return Decimal('1')
        return mod.multiplier

    @property
    def modification_percent(self) -> Decimal:
        return multiplier_to_percent(self.modification_multiplier)

    @property
    def modification_amount(self) -> Money:
        mod = self.data.cart_modification
        if not mod or mod.amount is None:
            return Money(0, self.currency)
        return mod.amount

    @property
    def total_base_markup_amount(self) -> Money:
        if self.base_markup_amount:
            return self.base_markup_amount
        elif self.data.base_markup_adjustment:
            return self.data.base_markup_adjustment
        return force_money_sum(
            (child.total_base_markup_amount for child in self.children),
            currency=self.currency,
        )

    @property
    def total_costmodel_cost_no_vat(self) -> Money:
        return self.cost_model_cost_modified or force_money_sum(
            (child.total_costmodel_cost_no_vat for child in self.children),
            currency=self.currency,
        )

    @property
    def total_gross_price_unmodified(self) -> Money:
        """
        Return complete INC VAT gross price of the tree from this node,
        excluding all cart modifications
        """
        if self.is_leaf():
            return self.node_gross_price_unmodified
        return force_money_sum(
            (child.total_gross_price_unmodified for child in self.children),
            currency=self.currency,
        )

    @property
    def total_gross_price_unmodified_excl_vat(self) -> Money:
        """
        Return complete EXCL. VAT gross price of the tree from this node,
        excluding all cart modifications
        """
        if self.is_leaf():
            return self.node_base_price
        return force_money_sum(
            (child.total_gross_price_unmodified_excl_vat for child in self.children),
            currency=self.currency,
        )

    @property
    def total_gross_price(self) -> Money:
        """Return complete INC VAT gross price of the tree from this node"""

        if self.is_leaf():
            return self.node_gross_price
        value = force_money_sum(
            (child.total_gross_price for child in self.children),
            currency=self.currency,
        )
        return self._apply_modification_to_value(value=value, include_vat=True)

    @property
    def total_gross_price_excl_vat(self) -> Money:
        """Return complete EXCL VAT gross price of the tree from this node"""
        if self.is_leaf():
            return self.node_base_price_modified
        value = force_money_sum(
            (child.total_gross_price_excl_vat for child in self.children),
            currency=self.currency,
        )
        return self._apply_modification_to_value(value=value, include_vat=False)

    @property
    def total_gross_price_with_root_mod(self) -> Money:
        if self.is_root():
            return self.total_gross_price
        return self.total_gross_price * self.tree.root_node.discount_modification_multiplier

    @property
    def total_gross_price_with_root_mod_excl_vat(self) -> Money:
        if self.is_root():
            return self.total_gross_price_excl_vat
        return self.total_gross_price_excl_vat * self.tree.root_node.discount_modification_multiplier

    def _get_modifications_difference(self, *, with_vat: bool, include_root_mod: bool) -> Money:
        if include_root_mod and (mod := self.tree.root_node.price_affecting_cart_modification):
            # The root modification takes precedence over the node's own modification, since we only should
            # have one of them for a given tree.
            gross = (
                self.total_gross_price_with_root_mod
                if with_vat
                else self.total_gross_price_with_root_mod_excl_vat
            )
        elif mod := self.price_affecting_cart_modification:
            gross = self.total_gross_price if with_vat else self.total_gross_price_excl_vat
        else:
            return Money(0, self.currency)

        base = gross

        if mod.amount is not None:
            amount = (mod.amount * self.vat_multiplier) if with_vat else mod.amount
            base -= amount
        elif mod.multiplier is not None:
            # If 100 % discount, the modifications difference is the negative of the unmodified price
            if mod.multiplier == 0:
                return -(
                    self.total_gross_price_unmodified
                    if with_vat
                    else self.total_gross_price_unmodified_excl_vat
                )

            base /= mod.multiplier

        return gross - base

    @property
    def modifications_difference(self) -> Money:
        return self._get_modifications_difference(with_vat=True, include_root_mod=False)

    @property
    def modifications_difference_with_root_mod(self) -> Money:
        return self._get_modifications_difference(with_vat=True, include_root_mod=True)

    @property
    def modifications_difference_with_root_mod_excl_vat(self) -> Money:
        return self._get_modifications_difference(with_vat=False, include_root_mod=True)

    def _apply_modification_to_value(self, *, value: Money, include_vat: bool) -> Money:
        """
        Apply the node's modification to the given value. This will only apply a modification
        if the value is non-zero and the node has a price-affecting cart modification.

        Args:
            value (Money): The value to be modified.
            include_vat (bool): Whether to include VAT in the modification amount.

        Returns:
            Money: The modified value.
        """
        if value.amount == 0:
            return value

        if not self.has_price_affecting_cart_modification:
            return value

        # NOTE: A database constraint protects us from having both a modification multiplier and a
        #       modification amount at the same time. We can therefore safely apply both here. If
        #       there is no multiplier, it will be 1, and if there is no amount it will be 0.
        value *= self.modification_multiplier
        if self.modification_amount:
            if include_vat:
                value += self.modification_amount * self.vat_multiplier
            else:
                value += self.modification_amount

        return value

    @property
    def is_detailed_invoicing_node(self) -> bool:
        if self.is_empty:
            return False
        if self.product_category.is_hardware_category:
            if self.data.hardware_override:
                return True
            if self.data.cost_item and self.parent and not self.parent.data.hardware_override:
                # Internal hardware nodes are invoiced if hardware override is set,
                # in that case all their children are ignored
                return True
        if self.data.extra_item and self.data.extra_item.is_hardware:
            return True
        if self.level == 2 and self.product_category.value.endswith('service'):
            return True
        return False

    @property
    def is_empty(self):
        """Whether the node has no price associated with it"""
        return not bool(self.total_gross_price_unmodified)

    @property
    def included_hardware(self) -> HardwareEntry:
        if self.product_category.is_hardware_category:
            if self.is_leaf() and self.data.cost_item and self.data.cost_item.hardware_model_id:
                return {(str(self.data.cost_item.hardware_model), self.data.cost_item.unit_count)}
            else:
                hardware: dict[str, int] = defaultdict(int)
                for node in self.children:
                    for model, count in node.included_hardware:
                        hardware[model] += count
                return set(hardware.items())
        return set()

    @property
    def legacy_product_category(self):
        """Helper to get the legacy product category for a node"""
        return get_legacy_product_for_product_category(
            self.product_category, is_extra_item=bool(self.data.extra_item)
        )

    @property
    def grouped_data_item(self) -> ShoppingCartInvoicingItem:
        """
        Return a group-level non-detailed shopping cart item for this node

        This item bundles all extra items and root level discounts into itself
        """
        assert self.level == 1, 'grouped_data_item is only supported for level 1 nodes'

        legacy_product_category = self.legacy_product_category
        name = legacy_product_category.display

        return ShoppingCartInvoicingItem(
            name=name,
            title=name,
            num_units=1,
            legacy_product_category=legacy_product_category,
            is_discount=False,
            total_price=self.total_gross_price_with_root_mod,
            total_price_excl_vat=self.total_gross_price_with_root_mod_excl_vat,
            unit_price=self.total_gross_price_with_root_mod,
            unit_price_excl_vat=self.total_gross_price_with_root_mod_excl_vat,
            vat_percent=self.vat_percent,
            item_type='service',
            purchase_model=self.purchase_model,
        )

    @property
    def detailed_data_item(self) -> ShoppingCartInvoicingItem:
        """Return a detailed shopping cart item for this node, based on what data this node is representing."""

        is_hardware_type = 'hardware' in self.product_category.value
        name: StrOrPromise = ''
        title = self.product_category.detailed_display_name
        num_units = 1

        if cost_item := self.data.cost_item:
            if cost_item.hardware_model:
                name = str(cost_item.hardware_model)
            else:
                name = cost_item.cost_category.display
            num_units = cost_item.unit_count
        elif included_hardware := self.data.hardware_override:
            name = '\n'.join([f'{count} × {model}' for model, count in included_hardware])
        elif extra_item := self.data.extra_item:
            title = extra_item.category.display
            name = extra_item.description
            num_units = extra_item.unit_count
        elif not is_hardware_type:
            name = self.product_category.detailed_description

        return ShoppingCartInvoicingItem(
            name=name,
            title=title,
            num_units=num_units,
            is_discount=False,
            legacy_product_category=self.legacy_product_category,
            total_price=self.total_gross_price,
            total_price_excl_vat=self.total_gross_price_excl_vat,
            unit_price=self.total_gross_price / num_units,
            unit_price_excl_vat=self.total_gross_price_excl_vat / num_units,
            vat_percent=self.vat_percent,
            item_type='hardware' if is_hardware_type else 'service',
            purchase_model=self.purchase_model,
        )
