```python
from datetime import datetime

@dataclass
class ShoppingCartInvoicingItem:
    name: StrOrPromise
    title: StrOrPromise
    num_units: int
    is_discount: bool
    legacy_product_category: str
    total_price: Money
    total_price_excl_vat: Money
    unit_price: Money
    unit_price_excl_vat: Money
    vat_percent: Decimal
    item_type: str
    purchase_model: PurchaseModel
    date: datetime   # New property to include date

class ProductNode(Node):

    # ... other properties and methods ...

    @property
    def detailed_data_item(self) -> ShoppingCartInvoicingItem:
        """Return a detailed shopping cart item for this node, based on what data this node is representing."""

        is_hardware_type = 'hardware' in self.product_category.value
        name: StrOrPromise = ''
        title = self.product_category.detailed_display_name
        num_units = 1

        if cost_item := self.data.cost_item:
            if cost_item.hardware_model:
                name = str(cost_item.hardware_model)
            else:
                name = cost_item.cost_category.display
            num_units = cost_item.unit_count
        elif included_hardware := self.data.hardware_override:
            name = '\n'.join([f'{count} × {model}' for model, count in included_hardware])
        elif extra_item := self.data.extra_item:
            title = extra_item.category.display
            name = extra_item.description
            num_units = extra_item.unit_count
        elif not is_hardware_type:
            name = self.product_category.detailed_description

        return ShoppingCartInvoicingItem(
            name=name,
            title=title,
            num_units=num_units,
            is_discount=False,
            legacy_product_category=self.legacy_product_category,
            total_price=self.total_gross_price,
            total_price_excl_vat=self.total_gross_price_excl_vat,
            unit_price=self.total_gross_price / num_units,
            unit_price_excl_vat=self.total_gross_price_excl_vat / num_units,
            vat_percent=self.vat_percent,
            item_type='hardware' if is_hardware_type else 'service',
            purchase_model=self.purchase_model,
            date=datetime.now()  # Include the current date
        )
